'use client'

import { useRouter } from 'next/navigation'
import { motion } from 'framer-motion'
import { useEffect, useState } from 'react'
import { useRegistrationStore } from '@/stores/registrationStore'
import { useNavigationStore } from '@/stores/navigationStore'
import { useVoiceStore } from '@/stores/voiceStore'
import TopBar from '@/components/TopBar'
import { speakWithSarvam } from '@/lib/sarvam-tts'
import { startListeningWithSarvam, type VoiceEngineConfig } from '@/lib/voice-engine'
import { DiyaIllustration } from '@/components/illustrations/PremiumIcons'

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.1, delayChildren: 0.3 }
  }
}

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.4 } }
}

export default function IdentityConfirmationPage() {
  const router = useRouter()
  const { setSection } = useNavigationStore()
  const { transcribedText, resetErrors } = useVoiceStore()
  const [isListening, setIsListening] = useState(false)
  const [confirmed, setConfirmed] = useState(false)

  useEffect(() => {
    setSection('identity-confirmation')
  }, [setSection])

  useEffect(() => {
    // Welcome voice intro on mount
    const timer = setTimeout(() => {
      void speakWithSarvam({
        text: 'नमस्ते पंडित जी। क्या आप एक पंडित हैं? यह app केवल पंडितों के लिए बना है।',
        languageCode: 'hi-IN',
      })
    }, 500)
    return () => clearTimeout(timer)
  }, [])

  const handleVoiceInput = () => {
    if (isListening) return

    resetErrors()
    setIsListening(true)

    const config: VoiceEngineConfig = {
      language: 'hi-IN',
      inputType: 'yes_no',
      isElderly: true,
      useSarvam: true,
      confidenceThreshold: 0.6,
      onStateChange: (state) => {
        console.log('[Identity] Voice state:', state)
        if (state === 'IDLE' || state === 'SUCCESS' || state === 'FAILURE') {
          setIsListening(false)
        }
      },
      onResult: (result) => {
        console.log('[Identity] Voice result:', result)
        const answer = result.transcript.toLowerCase()

        if (answer.includes('haan') || answer.includes('yes') || answer.includes('correct')) {
          setConfirmed(true)
          void speakWithSarvam({
            text: 'धन्यवाद। आपकी पहचान की पुष्टि हो गई है। अब आगे बढ़ते हैं।',
            languageCode: 'hi-IN',
          })
          setTimeout(() => {
            router.push('/language')
          }, 1500)
        } else if (answer.includes('nahi') || answer.includes('no') || answer.includes('galat')) {
          void speakWithSarvam({
            text: 'कोई बात नहीं। कृपया सही जानकारी दें या सहायता के लिए संपर्क करें।',
            languageCode: 'hi-IN',
          })
          setTimeout(() => {
            router.push('/')
          }, 2000)
        }

        setIsListening(false)
      },
      onError: (error) => {
        console.warn('[Identity] Voice error:', error)
        setIsListening(false)

        if (error === 'KEYBOARD_FALLBACK') {
          // Show keyboard options
          setConfirmed(true)
          router.push('/language')
        }
      },
    }

    const cleanup = startListeningWithSarvam(config)

    return () => {
      cleanup()
    }
  }

  const handleManualConfirm = () => {
    setConfirmed(true)
    void speakWithSarvam({
      text: 'धन्यवाद। आपकी पहचान की पुष्टि हो गई है।',
      languageCode: 'hi-IN',
    })
    setTimeout(() => {
      router.push('/language')
    }, 1000)
  }

  const handleManualDeny = () => {
    void speakWithSarvam({
      text: 'कोई बात नहीं।',
      languageCode: 'hi-IN',
    })
    setTimeout(() => {
      router.push('/')
    }, 1000)
  }

  return (
    <div className="min-h-dvh flex flex-col bg-surface-base relative overflow-hidden">
      {/* Sacred Gradient Backdrop - Using CSS class instead of inline style */}
      <div className="fixed inset-0 bg-sacred pointer-events-none -z-10" />

      {/* Diya halo effect behind main content - matching identity_confirmation_e_02 */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[400px] xs:w-[450px] sm:w-[500px] h-[400px] xs:h-[450px] sm:h-[500px] diya-halo rounded-full -z-10 blur-3xl" />

      {/* Top Bar */}
      <TopBar
        showBack
        onBack={() => router.back()}
      />

      {/* Main Content */}
      <main className="flex-1 px-6 pb-8 pt-4 flex flex-col">
        <motion.div
          variants={containerVariants}
          initial="hidden"
          animate="visible"
          className="flex-1 flex flex-col"
        >
          {/* Icon/Illustration with shimmer effect and glow */}
          <motion.div variants={itemVariants} className="mb-10 flex justify-center relative">
            {/* Glow effect behind diya */}
            <div className="absolute inset-0 bg-saffron/20 rounded-full blur-xl" />
            <div className="shimmer-text">
              <DiyaIllustration size="lg" animated={true} />
            </div>
          </motion.div>

          {/* Heading - matching identity_confirmation_e_02 */}
          <motion.h1
            variants={itemVariants}
            className="font-serif text-4xl font-bold text-primary tracking-tight leading-tight text-center mb-3 font-devanagari"
          >
            नमस्ते, पंडित जी! 🙏
          </motion.h1>

          {/* Description */}
          <motion.p
            variants={itemVariants}
            className="text-text-secondary text-xl font-medium leading-relaxed text-center mb-12 font-devanagari"
          >
            HmarePanditJi आपके लिए है
          </motion.p>

          {/* Voice Input Card */}
          <motion.div
            variants={itemVariants}
            className="bg-surface-card rounded-2xl p-6 shadow-card mb-6"
          >
            <div className="flex flex-col items-center">
              {/* Voice Button with saffron-glow-active */}
              <motion.button
                whileTap={{ scale: 0.95 }}
                onClick={handleVoiceInput}
                disabled={isListening}
                className={`w-20 h-20 rounded-full flex items-center justify-center mb-4 transition-all saffron-glow-active ${isListening
                  ? 'bg-saffron-light animate-pulse'
                  : 'bg-saffron shadow-btn-saffron'
                  }`}
              >
                {isListening ? (
                  <div className="flex items-center gap-1">
                    {[1, 2, 3].map((i) => (
                      <motion.div
                        key={i}
                        className="w-1.5 bg-saffron-dark rounded-full"
                        animate={{
                          height: [8, 20, 8],
                        }}
                        transition={{
                          duration: 0.6,
                          repeat: Infinity,
                          delay: i * 0.15,
                        }}
                      />
                    ))}
                  </div>
                ) : (
                  <span className="material-symbols-outlined text-3xl text-white">mic</span>
                )}
              </motion.button>

              <p className="text-text-secondary text-center font-devanagari">
                {isListening ? 'सुन रहे हैं...' : 'उत्तर देने के लिए माइक दबाएं'}
              </p>

              {/* Transcribed text (if any) */}
              {transcribedText && (
                <motion.p
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="mt-3 text-saffron font-medium text-center font-devanagari"
                >
                  आपने कहा: &quot;{transcribedText}&quot;
                </motion.p>
              )}
            </div>
          </motion.div>

          {/* Feature Cards - Bento style matching identity_confirmation_e_02 */}
          <motion.div variants={itemVariants} className="w-full space-y-5 mb-6">
            {/* Dakshina Feature */}
            <div className="bg-surface-container-lowest p-6 rounded-2xl shadow-[0px_8px_24px_rgba(144,77,0,0.04)] border-l-4 border-primary flex items-center gap-5">
              <div className="w-14 h-14 bg-primary-fixed rounded-xl flex items-center justify-center text-3xl shimmer-text">
                💰
              </div>
              <div>
                <h3 className="font-headline text-lg font-bold text-text-primary">तय दक्षिणा</h3>
                <p className="text-text-secondary leading-relaxed">हर अनुष्ठान के लिए सही और स्पष्ट मूल्य</p>
              </div>
            </div>

            {/* Voice Control Feature */}
            <div className="bg-surface-container-lowest p-6 rounded-2xl shadow-[0px_8px_24px_rgba(144,77,0,0.04)] border-l-4 border-primary flex items-center gap-5">
              <div className="w-14 h-14 bg-primary-fixed rounded-xl flex items-center justify-center text-3xl shimmer-text">
                🎙️
              </div>
              <div>
                <h3 className="font-headline text-lg font-bold text-text-primary">सरल वॉइस कंट्रोल</h3>
                <p className="text-text-secondary leading-relaxed">बोलकर काम करें, टाइपिंग की जरूरत नहीं</p>
              </div>
            </div>

            {/* Payment Feature */}
            <div className="bg-surface-container-lowest p-6 rounded-2xl shadow-[0px_8px_24px_rgba(144,77,0,0.04)] border-l-4 border-primary flex items-center gap-5">
              <div className="w-14 h-14 bg-primary-fixed rounded-xl flex items-center justify-center text-3xl shimmer-text">
                ⚡
              </div>
              <div>
                <h3 className="font-headline text-lg font-bold text-text-primary">त्वरित भुगतान</h3>
                <p className="text-text-secondary leading-relaxed">सीधे आपके बैंक खाते में तुरंत ट्रांसफर</p>
              </div>
            </div>
          </motion.div>

          {/* Joining Free Badge */}
          <motion.div variants={itemVariants} className="flex items-center justify-center gap-2 bg-secondary-container/30 py-3 rounded-full border border-secondary/10 mb-4">
            <span className="material-symbols-outlined text-secondary material-symbols-filled">check_circle</span>
            <span className="font-label text-on-secondary-container font-semibold tracking-wide">पूर्णतः निःशुल्क</span>
          </motion.div>

          {/* Primary CTA Button */}
          <motion.button
            variants={itemVariants}
            whileTap={{ scale: 0.98 }}
            onClick={handleManualConfirm}
            className="w-full h-16 bg-gradient-to-b from-primary-container to-primary text-white font-headline text-lg font-bold rounded-2xl shadow-[0px_12px_24px_rgba(144,77,0,0.2)] active:scale-95 transition-transform flex items-center justify-center gap-3"
          >
            <span>हाँ, मैं पंडित हूँ — पंजीकरण शुरू करें</span>
            <span className="material-symbols-outlined">arrow_forward</span>
          </motion.button>
        </motion.div>
      </main>
    </div>
  )
}

'use client'

import { useEffect, useRef, useState } from 'react'
import { useRouter } from 'next/navigation'
import { motion } from 'framer-motion'
import { speakWithSarvam, stopCurrentSpeech } from '@/lib/sarvam-tts'
import { useOnboardingStore } from '@/stores/onboardingStore'
import { LANGUAGE_LIST_SCREEN } from '@/lib/voice-scripts'
import { replaceScriptPlaceholders } from '@/lib/voice-scripts'
import { ALL_LANGUAGES, LANGUAGE_DISPLAY, type SupportedLanguage } from '@/lib/onboarding-store'

export default function LanguageListScreen() {
  const router = useRouter()
  const { setPhase, setPendingLanguage } = useOnboardingStore()
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedLanguage, setSelectedLanguage] = useState<SupportedLanguage | null>(null)
  const [showKeyboard, setShowKeyboard] = useState(false)
  const hasSpokenRef = useRef(false)
  const isMountedRef = useRef(true)

  useEffect(() => {
    isMountedRef.current = true
    const timer = setTimeout(() => {
      if (isMountedRef.current && !hasSpokenRef.current) {
        hasSpokenRef.current = true
        void speakWithSarvam({
          text: LANGUAGE_LIST_SCREEN.scripts.main.hindi,
          languageCode: 'hi-IN',
        })
      }
    }, 600)
    return () => { isMountedRef.current = false; clearTimeout(timer); stopCurrentSpeech(); }
  }, [])

  const handleSelect = (lang: SupportedLanguage) => {
    setSelectedLanguage(lang)
    setPendingLanguage(lang)
    void speakWithSarvam({
      text: `${lang} — क्या यह सही है? 'हाँ' बोलें।`,
      languageCode: 'hi-IN',
    })
    setTimeout(() => router.push('/language-confirm'), 500)
  }

  const filteredLanguages = ALL_LANGUAGES.filter(lang => {
    const info = LANGUAGE_DISPLAY[lang]
    return info.latinName.toLowerCase().includes(searchQuery.toLowerCase()) || info.nativeName.includes(searchQuery)
  })

  return (
    <main className="w-full min-h-dvh max-w-[390px] xs:max-w-[430px] mx-auto bg-surface-base relative flex flex-col overflow-hidden shadow-2xl">
      {/* Top Bar */}
      <header className="min-h-[52px] xs:min-h-[56px] sm:min-h-[72px] px-4 xs:px-6 flex items-center justify-between border-b border-border-default sticky top-0 bg-surface-base z-50">
        <button onClick={() => router.back()} className="min-h-[52px] xs:min-h-[56px] min-w-[52px] xs:min-w-[56px] p-2 hover:bg-black/5 rounded-full transition-colors active:scale-95" aria-label="Go back">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" /></svg>
        </button>
        <button onClick={() => {}} className="min-h-[52px] xs:min-h-[56px] min-w-[52px] xs:min-w-[56px] text-2xl active:opacity-50">🌐</button>
      </header>

      {/* Title */}
      <div className="px-4 xs:px-6 pt-4 xs:pt-5 pb-3 xs:pb-4">
        <h1 className="text-xl xs:text-2xl sm:text-[28px] font-bold text-text-primary leading-tight">अपनी भाषा चुनें</h1>
      </div>

      {/* Voice Search */}
      <section className="px-4 xs:px-6 mb-3 xs:mb-4">
        <div onClick={() => setShowKeyboard(!showKeyboard)} className="bg-saffron-lt border-2 border-saffron rounded-2xl p-3 xs:p-4 flex items-center gap-3 xs:gap-4 cursor-pointer active:scale-[0.98] transition-transform">
          <div className="relative w-14 h-14 xs:w-16 xs:h-16 flex items-center justify-center bg-white rounded-full shadow-sm">
            <svg className="h-6 w-6 xs:h-7 xs:w-7 text-saffron relative z-10" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" /></svg>
          </div>
          <div>
            <p className="text-lg xs:text-xl sm:text-[24px] font-bold text-text-primary">{showKeyboard ? 'भाषा खोजें...' : 'भाषा का नाम बोलें'}</p>
            <p className="text-base xs:text-lg sm:text-[22px] text-saffron mt-1">जैसे: &apos;Hindi&apos;, &apos;Tamil&apos;, &apos;Bengali&apos;</p>
          </div>
        </div>
      </section>

      {/* Divider */}
      <div className="px-4 xs:px-6 mb-3 xs:mb-4 text-center"><span className="text-saffron/60 text-sm xs:text-base sm:text-lg font-medium">─── या नीचे से चुनें ───</span></div>

      {/* Text Search */}
      <section className="px-4 xs:px-6 mb-3 xs:mb-4">
        <div className="relative">
          <span className="absolute inset-y-0 left-2 xs:left-3 flex items-center"><svg className="h-5 w-5 xs:h-6 xs:w-6 text-saffron/60" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></span>
          <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} className="w-full bg-white border border-outline-variant rounded-xl py-3 xs:py-4 pl-10 xs:pl-12 pr-3 xs:pr-4 text-text-primary placeholder-saffron/60 focus:outline-none focus:ring-2 focus:ring-primary focus:border-saffron transition-all text-base xs:text-lg sm:text-[22px] min-h-[52px] xs:min-h-[56px] sm:min-h-[80px]" placeholder="भाषा खोजें..." type="text" />
        </div>
      </section>

      {/* Language Grid */}
      <section className="px-4 xs:px-6 flex-1 overflow-y-auto pb-6 xs:pb-8">
        <div className="grid grid-cols-2 gap-2 xs:gap-3">
          {filteredLanguages.map((lang, idx) => {
            const info = LANGUAGE_DISPLAY[lang]
            const isSelected = selectedLanguage === lang
            return (
              <motion.button key={lang} initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.04 * idx }} onClick={() => handleSelect(lang)} className={`relative flex flex-col items-center justify-center min-h-[52px] xs:min-h-[56px] sm:min-h-[96px] rounded-xl px-3 xs:px-4 sm:px-5 transition-all ${isSelected ? 'bg-saffron-lt border-2 border-saffron' : 'bg-white border border-outline-variant hover:border-saffron'}`}>
                <span className={`text-lg xs:text-xl sm:text-[26px] font-bold leading-tight ${isSelected ? 'text-saffron' : 'text-text-primary'}`}>{info.nativeName}</span>
                <span className="text-sm xs:text-base sm:text-[22px] text-saffron leading-tight mt-1">{info.latinName}</span>
                {isSelected && (<div className="absolute top-1 xs:top-2 right-1 xs:right-2"><svg className="h-4 w-4 xs:h-5 xs:w-5 text-saffron" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" /></svg></div>)}
              </motion.button>
            )
          })}
        </div>
      </section>
    </main>
  )
}

'use client'

import { useEffect, useState, FormEvent } from 'react'
import { useRouter, useParams } from 'next/navigation'
import { motion } from 'framer-motion'
import { useRegistrationStore } from '@/stores/registrationStore'
import { useNavigationStore } from '@/stores/navigationStore'
import { speakWithSarvam } from '@/lib/sarvam-tts'

interface ReferralValidationResponse {
  valid: boolean
  referrerName?: string
  benefit?: string
  referrerBenefit?: string
  error?: string
}

export default function ReferralLandingPage() {
  const router = useRouter()
  const params = useParams()
  const { setReferralCode, setCurrentStep } = useRegistrationStore()
  const { navigate, setSection } = useNavigationStore()
  const [isValid, setIsValid] = useState<boolean | null>(null)
  const [referrerName, setReferrerName] = useState('')
  const [benefit, setBenefit] = useState('')
  const [isLoading, setIsLoading] = useState(true)

  // Manual entry state
  const [manualCode, setManualCode] = useState('')
  const [validatingManual, setValidatingManual] = useState(false)
  const [manualError, setManualError] = useState('')

  const referralCode = (params?.code as string) ?? ''

  useEffect(() => {
    navigate(`/referral/${referralCode}`, 'identity')
    // eslint-disable-next-line react-hooks/exhaustive-deps
    setSection('identity')
  }, [navigate, referralCode])

  useEffect(() => {
    // Validate referral code from URL
    const validateCode = async () => {
      if (!referralCode || referralCode.length < 6) {
        setIsValid(false)
        setIsLoading(false)
        return
      }

      try {
        const response = await fetch('/api/referral/validate', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ code: referralCode }),
        })

        const data: ReferralValidationResponse = await response.json()

        if (data.valid) {
          setIsValid(true)
          setReferrerName(data.referrerName || 'Pandit Ji')
          setBenefit(data.benefit || '')
          setReferralCode(referralCode.toUpperCase())
        } else {
          setIsValid(false)
        }
      } catch (error) {
        console.error('[Referral] Validation error:', error)
        setIsValid(false)
      } finally {
        setIsLoading(false)
      }
    }

    validateCode()
  }, [referralCode, setReferralCode])

  useEffect(() => {
    if (isValid !== null) {
      const timer = setTimeout(() => {
        if (isValid) {
          void speakWithSarvam({
            text: `बहुत अच्छा! ${referrerName} ने आपको आमंत्रित किया है। अब पंजीकरण शुरू करें।`,
            languageCode: 'hi-IN',
          })
        } else {
          void speakWithSarvam({
            text: 'यह रेफरल कोड मान्य नहीं है। कृपया जांचें और फिर से कोशिश करें।',
            languageCode: 'hi-IN',
          })
        }
      }, 500)
      return () => clearTimeout(timer)
    }
  }, [isValid, referrerName])

  const handleContinue = () => {
    setCurrentStep('language')
    router.push('/identity')
  }

  const handleGoHome = () => {
    router.push('/')
  }

  // F-DEV2-05: Manual referral code validation
  const handleManualValidate = async (e: FormEvent) => {
    e.preventDefault()
    setManualError('')

    // Validate format: 6-10 alphanumeric
    const codeFormat = /^[A-Za-z0-9]{6,10}$/
    if (!codeFormat.test(manualCode)) {
      setManualError('कोड 6-10 अक्षरों का होना चाहिए')
      return
    }

    setValidatingManual(true)

    try {
      const response = await fetch('/api/referral/validate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ code: manualCode }),
      })

      const data: ReferralValidationResponse = await response.json()

      if (data.valid) {
        setReferralCode(manualCode.toUpperCase())
        setReferrerName(data.referrerName || 'Pandit Ji')
        setBenefit(data.benefit || '')
        setIsValid(true)
        setManualCode('')

        void speakWithSarvam({
          text: `बहुत अच्छा! ${data.referrerName} ने आपको आमंत्रित किया है।`,
          languageCode: 'hi-IN',
        })
      } else {
        setManualError(data.error || 'Invalid code')
        void speakWithSarvam({
          text: 'यह कोड मान्य नहीं है। कृपया जांचें और फिर से कोशिश करें।',
          languageCode: 'hi-IN',
        })
      }
    } catch (error) {
      console.error('[Referral] Manual validation error:', error)
      setManualError('Validation failed. Please try again.')
    } finally {
      setValidatingManual(false)
    }
  }

  if (isValid === null) {
    return (
      <main className="min-h-dvh flex flex-col items-center justify-center bg-surface-base">
        <div className="w-16 h-16 border-4 border-saffron border-t-transparent rounded-full animate-spin" />
