    } catch (error) {
      console.error('[MobilePage] Error in handleConfirm:', error)
      setNetworkError('नेटवर्क धीमा है। कृपया पुनः प्रयास करें।')
      speakWithSarvam({
        text: 'नेटवर्क धीमा है। कृपया पुनः प्रयास करें।',
