export default function RegistrationFlow({ onBack }: { onBack: () => void }) {
  const [step, setStep] = useState<RegStep>('welcome');
  const [data, setData] = useState<RegData>({ mobile: '', name: '', city: '' });
  const [language, setLanguage] = useState<SupportedLanguage>('Hindi');

  useEffect(() => {
    const saved = loadOnboardingState();
    setLanguage(saved.selectedLanguage);
    saveOnboardingState({ ...saved, phase: 'TUTORIAL_CTA', tutorialCompleted: false });
    void speakWithSarvam({
      text: 'बहुत अच्छा पंडित जी। अब Registration शुरू करते हैं। बिल्कुल मुफ़्त — दस मिनट लगेंगे।',
      languageCode: 'hi-IN',
      speaker: 'ratan',
      onEnd: () => setStep('mobile'),
    });
  }, []);

  const goBackToTutorial = () => {
    stopCurrentSpeech();
    const saved = loadOnboardingState();
    saveOnboardingState({ ...saved, phase: 'TUTORIAL_CTA', tutorialCompleted: false });
    onBack();
  };

  if (step === 'welcome') {
    return (
      <main className="min-h-dvh w-full max-w-[390px] xs:max-w-[430px] mx-auto bg-surface-base font-body flex flex-col shadow-2xl">
        {/* Large Prominent Om Symbol */}
        <div className="text-center py-6 xs:py-8 bg-gradient-to-b from-saffron-light/50 to-transparent border-b-2 border-saffron/30">
          <p className="text-8xl xs:text-9xl sm:text-[120px] font-bold text-saffron animate-gentle-float om-glow" aria-label="पवित्र ओम प्रतीक">ॐ</p>
          <p className="text-2xl xs:text-3xl sm:text-[32px] font-bold text-saffron mt-2 xs:mt-3 font-devanagari">स्वागतम्</p>
        </div>
        <header className="pt-4 xs:pt-6 px-4 xs:px-6 pb-2 flex items-center gap-2 xs:gap-3 shrink-0">
          <button onClick={goBackToTutorial} className="w-16 h-16 xs:w-20 xs:h-20 -ml-2 xs:-ml-3 flex items-center justify-center text-saffron hover:bg-saffron-light rounded-full min-h-[52px] xs:min-h-[56px] min-w-[52px] xs:min-w-[56px] focus:ring-4 focus:ring-saffron focus:outline-none" aria-label="पीछे जाएं">
            <svg width="32" height="32" xs-width="40" xs-height="40" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" viewBox="0 0 24 24">
              <path d="M15 18l-6-6 6-6" />
            </svg>
          </button>
        </header>
        <div className="flex-1 flex items-center justify-center">
          <div className="text-center px-4 xs:px-6">
            <div className="text-7xl xs:text-8xl sm:text-[88px] mb-4 xs:mb-6 animate-gentle-float">🙏</div>
            <p className="text-2xl xs:text-3xl sm:text-[32px] font-bold text-text-primary">तैयार हो रहे हैं...</p>
            <div className="flex justify-center gap-3 xs:gap-4 mt-6 xs:mt-8">
              <div className="w-4 h-4 xs:w-5 xs:h-5 bg-saffron rounded-full animate-bounce delay-0" />
              <div className="w-4 h-4 xs:w-5 xs:h-5 bg-saffron rounded-full animate-bounce delay-150" />
              <div className="w-4 h-4 xs:w-5 xs:h-5 bg-saffron rounded-full animate-bounce delay-300" />
            </div>
          </div>
        </div>
      </main>
    );
  }


  if (step === 'mobile') {
    return (
      <MobileNumberScreen
        language={language}
        onComplete={(mobile: string) => {
          setData(prev => ({ ...prev, mobile }));
          setStep('otp');
        }}
        onBack={() => goBackToTutorial()}
      />
    );
  }

  if (step === 'otp') {
    return (
      <OTPScreen
        mobile={data.mobile}
        language={language}
        onComplete={() => setStep('profile_name')}
        onBack={() => setStep('mobile')}
      />
    );
  }

  if (step === 'profile_name') {
    return (
      <ProfileNameScreen
        language={language}
        step={3}
        onComplete={(name) => {
          setData(prev => ({ ...prev, name }));
          setStep('profile_city');
        }}
        onBack={() => setStep('otp')}
      />
    );
  }

  if (step === 'profile_city') {
    const savedCity = typeof window !== 'undefined'
      ? JSON.parse(localStorage.getItem('hpj-onboarding') ?? '{}')?.detectedCity ?? ''
      : '';

    return (
      <ProfileCityScreen
        language={language}
        detectedCity={savedCity}
        onComplete={(city: string) => {
          setData(prev => ({ ...prev, city }));
          setStep('complete');
        }}
        onBack={() => setStep('profile_name')}
      />
    );
  }

  if (step === 'complete') {
    return <RegistrationCompleteScreen name={data.name || 'पंडित जी'} language={language} />;
  }

  return null;
}

'use client';

import React, { useEffect, useRef, useState } from 'react';
import { motion } from 'framer-motion';
import { speak, startListening, stopListening, stopSpeaking } from '@/lib/voice-engine';
