'use client'

import React, { useEffect, useState } from 'react'
import { IllustrationSkeleton } from './Skeleton'

interface LazyIllustrationProps {
  name: string
  size?: 'sm' | 'md' | 'lg'
  animated?: boolean
}

export function LazyIllustration({ name, size = 'md', animated = true }: LazyIllustrationProps) {
  const [Illustration, setIllustration] = useState<React.ComponentType<any> | null>(null)
  const [error, setError] = useState(false)

  useEffect(() => {
    let mounted = true

    const loadIllustration = async () => {
      try {
        const module = await import(`@/components/illustrations/${name}.tsx`)
        if (mounted) {
          setIllustration(() => module.default)
        }
      } catch (err) {
        console.error(`Failed to load illustration: ${name}`, err)
        if (mounted) {
          setError(true)
        }
      }
    }

    loadIllustration()

    return () => {
      mounted = false
    }
  }, [name])

  if (error) {
    // Fallback emoji illustration
    return (
      <div className={`flex items-center justify-center bg-saffron-lt rounded-full ${
        size === 'lg' ? 'w-48 h-48 text-7xl' :
        size === 'md' ? 'w-32 h-32 text-5xl' :
        'w-20 h-20 text-3xl'
      }`}>
        🙏
      </div>
    )
  }

  if (!Illustration) {
    return <IllustrationSkeleton size={size} />
  }

  return <Illustration size={size} animated={animated} />
}

'use client'

import { motion, AnimatePresence } from 'framer-motion'
import { useEffect, useState } from 'react'
import { useVoiceStore } from '@/stores/voiceStore'
import { speakWithSarvam } from '@/lib/sarvam-tts'

/**
 * Ambient Noise Pre-Check Flow
 *
 * As specified in HPJ_Voice_Complete_Guide.md:
 * - Detects ambient noise >85dB before STT session starts (temple bells, heavy traffic, crowds)
 * - Interrupts flow with friendly warning
 * - Suggests keyboard mode or quieter location
 * - Prevents Pandit Ji from getting frustrated by failed voice input
 *
 * BUG-MEDIUM-04 FIX: Threshold raised from 65dB to 85dB to prevent false-triggering
 * in quiet/normal environments. 65dB is normal conversation level.
 * 85dB is genuinely loud (temple bells, heavy traffic, crowds).
 *
 * Usage: Wrap voice input screens with this component or use the hook
 */

interface NoiseWarningOverlayProps {
  onSwitchToKeyboard?: () => void
  onRetry?: () => void
  isVisible: boolean
}

export function NoiseWarningOverlay({
  onSwitchToKeyboard,
  onRetry,
  isVisible,
}: NoiseWarningOverlayProps) {
  const [noiseLevel, setNoiseLevel] = useState(0)
  const { ambientNoiseLevel, resetErrors } = useVoiceStore()

  useEffect(() => {
    setNoiseLevel(ambientNoiseLevel)
  }, [ambientNoiseLevel])

  useEffect(() => {
    if (isVisible && ambientNoiseLevel > 85) {
      // Play warning voice
      void speakWithSarvam({
        text: 'मंदिर में शोर है। कृपया शांत जगह जाएं या बटन दबाकर चुनें।',
        languageCode: 'hi-IN',
        pace: 0.85,
      })
    }
  }, [isVisible, ambientNoiseLevel])

  const getNoiseMessage = (level: number) => {
    if (level > 85) {
      return {
        title: 'बहुत ज्यादा शोर',
        subtitle: 'आवाज़ सुनाई नहीं दे रही',
