export function detectLanguageName(transcript: string): string | null {
  const normalized = transcript.toLowerCase().trim()
  const languageAliases: Record<string, string> = {
    'hindi': 'Hindi',
    'hindee': 'Hindi',
    'bhojpuri': 'Bhojpuri',
    'bhojpori': 'Bhojpuri',
    'bhojpuriya': 'Bhojpuri',
    'maithili': 'Maithili',
    'maithil': 'Maithili',
    'bengali': 'Bengali',
    'bangla': 'Bengali',
    'bangali': 'Bengali',
    'tamil': 'Tamil',
    'tamizh': 'Tamil',
    'tameel': 'Tamil',
    'telugu': 'Telugu',
    'telegu': 'Telugu',
    'kannada': 'Kannada',
    'kannad': 'Kannada',
    'malayalam': 'Malayalam',
    'malayali': 'Malayalam',
    'marathi': 'Marathi',
    'gujarati': 'Gujarati',
    'gujrati': 'Gujarati',
    'gujarathi': 'Gujarati',
    'sanskrit': 'Sanskrit',
    'sanskrith': 'Sanskrit',
    'english': 'English',
    'angrezi': 'English',
    'odia': 'Odia',
    'oriya': 'Odia',
    'punjabi': 'Punjabi',
    'panjabi': 'Punjabi',
    'assamese': 'Assamese',
  }

  for (const [alias, language] of Object.entries(languageAliases)) {
    if (normalized.includes(alias)) return language
  }

  return null
}

